(() => {
  const STICKY_SELECTOR = '.kam-sticky-cart-banner';
  const ADD_TO_CART_SELECTOR = 'button[aria-label="Ajouter au panier"]';
  const PRODUCT_TITLE_SELECTOR = '#pdp_product_title';

  const getText = (selector) => document.querySelector(selector)?.textContent?.replace(/\s+/g, ' ').trim() || '';

  const getMainAddToCartButton = () => {
    const buttons = Array.from(document.querySelectorAll(ADD_TO_CART_SELECTOR));
    return buttons.find((button) => !button.closest(STICKY_SELECTOR)) || null;
  };

  const getProductImage = () => {
    const image = document.querySelector('#hero-image img, #mobile-image-carousel img, label img');
    return image?.currentSrc || image?.src || '';
  };

  const getProductDetails = () => ({
    title: getText(PRODUCT_TITLE_SELECTOR),
    subtitle: getText('#pdp_product_subtitle'),
    price: getText('#price-container span'),
    description: getText('#product-description-container p'),
    image: getProductImage()
  });

  const createProductMedia = ({ image, title }) => {
    const media = document.createElement('div');
    media.className = 'kam-sticky-cart-banner__media';

    if (image) {
      const img = document.createElement('img');
      img.src = image;
      img.alt = title || '';
      media.appendChild(img);
    }

    return media;
  };

  const createProductInfo = ({ title, subtitle, description }) => {
    const info = document.createElement('div');
    info.className = 'kam-sticky-cart-banner__info';

    const productTitle = document.createElement('div');
    productTitle.className = 'kam-sticky-cart-banner__title';
    productTitle.textContent = title;

    const productSubtitle = document.createElement('div');
    productSubtitle.className = 'kam-sticky-cart-banner__subtitle';
    productSubtitle.textContent = subtitle;

    const productDescription = document.createElement('div');
    productDescription.className = 'kam-sticky-cart-banner__description';
    productDescription.textContent = description;

    info.append(productTitle, productSubtitle, productDescription);
    return info;
  };

  const createStickyButton = (mainButton) => {
    const button = document.createElement('button');
    button.type = 'button';
    button.className = `${mainButton.className || ''} kam-sticky-cart-banner__button`.trim();
    button.setAttribute('aria-label', mainButton.getAttribute('aria-label') || 'Ajouter au panier');
    button.innerHTML = mainButton.innerHTML || '<span>Ajouter au panier</span>';

    Kameleoon.API.Utils.addUniversalClickListener(button, (event) => {
      event.preventDefault();
      event.stopPropagation();
      const currentMainButton = getMainAddToCartButton();

      if (currentMainButton) {
        currentMainButton.click();
      }
    });

    return button;
  };

  const updateStickyVisibility = (banner, mainButton) => {
    const rect = mainButton.getBoundingClientRect();
    const isMainButtonVisible = rect.bottom > 0 && rect.top < window.innerHeight;
    banner.classList.toggle('kam-sticky-cart-banner--visible', !isMainButtonVisible);
    document.documentElement.classList.toggle('kam-sticky-cart-banner-is-visible', !isMainButtonVisible);
  };

  const bindVisibilityEvents = (banner, mainButton) => {
    let ticking = false;

    const requestUpdate = () => {
      if (ticking) return;

      ticking = true;
      window.requestAnimationFrame(() => {
        updateStickyVisibility(banner, mainButton);
        ticking = false;
      });
    };

    Kameleoon.API.Utils.addEventListener(window, 'scroll', requestUpdate);
    Kameleoon.API.Utils.addEventListener(window, 'resize', requestUpdate);
    updateStickyVisibility(banner, mainButton);
  };

  const removeExistingBanner = () => {
    document.querySelector(STICKY_SELECTOR)?.remove();
    document.documentElement.classList.remove('kam-sticky-cart-banner-is-visible');
  };

  const buildStickyBanner = (mainButton) => {
    removeExistingBanner();

    const details = getProductDetails();
    const banner = document.createElement('aside');
    banner.className = 'kameleoonInsert kam-sticky-cart-banner';
    banner.setAttribute('aria-label', 'Résumé produit et ajout au panier');

    const inner = document.createElement('div');
    inner.className = 'kam-sticky-cart-banner__inner';

    const product = document.createElement('div');
    product.className = 'kam-sticky-cart-banner__product';
    product.append(createProductMedia(details), createProductInfo(details));

    const actions = document.createElement('div');
    actions.className = 'kam-sticky-cart-banner__actions';
    actions.appendChild(createStickyButton(mainButton));

    const price = document.createElement('div');
    price.className = 'kam-sticky-cart-banner__price';
    price.textContent = details.price;

    inner.append(product, price, actions);
    banner.appendChild(inner);
    document.body.appendChild(banner);

    bindVisibilityEvents(banner, mainButton);
  };

  Kameleoon.API.Core.runWhenElementPresent(ADD_TO_CART_SELECTOR, (elements) => {
    const mainButton = Array.from(elements).find((button) => !button.closest(STICKY_SELECTOR)) || getMainAddToCartButton();

    if (mainButton) {
      buildStickyBanner(mainButton);
    }
  });
})();

