Here is the current javascript code applied to the page to update:

(() => {
  const KAMELEOON_STORAGE_KEY = 'kam_exit_cart_data';
  const CART_URL = 'https://www.boulanger.com/checkout/cart';
  const LOYALTY_URL = 'https://www.boulanger.com/evenement/espace-fidelite';
  const state = {
    isOpen: false,
    lastTrigger: 0
  };

  const normalizeText = (value) => (value || '').replace(/\s+/g, ' ').trim();

  const escapeHtml = (value) => normalizeText(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');

  const formatSlug = (value) => normalizeText(value)
    .replace(/_/g, ' ')
    .replace(/\s+/g, ' ')
    .replace(/\b\w/g, (letter) => letter.toUpperCase());

  const formatPrice = (value) => {
    if (!value && value !== 0) return '';
    const numberValue = Number(value);
    if (Number.isNaN(numberValue)) return normalizeText(value).replace('currentPrice', '').trim();
    return `${numberValue.toLocaleString('fr-FR', { minimumFractionDigits: numberValue % 1 ? 2 : 0, maximumFractionDigits: 2 })}€`;
  };

  const getImageFromEan = (ean) => {
    if (!ean) return '';
    return `https://boulanger.scene7.com/is/image/Boulanger/${ean}_h_f_l_0?wid=148&hei=148&resMode=sharp2&op_usm=1.75,0.3,2,0`;
  };

  const extractSize = (name, rowText) => {
    const source = `${name} ${rowText || ''}`;
    const explicitSize = source.match(/taille\s*:?\s*([A-Za-z0-9À-ÿ\-\/\.\s]{1,24})(?:\s{2,}|\||,|;|$)/i);
    const inchSize = source.match(/(\d{2,3})\s*(?:pouces|''|″|")/i);
    const cmSize = source.match(/(\d{2,3})\s*cm/i);
    const modelSize = source.match(/\b(?:TQ|QE|QN|KD|XR|OLED|OLEDTV|TX|LC|55|65)?(\d{2})(?=[A-Z]{1,4}\d|[A-Z]{2,})/i);

    if (explicitSize) return normalizeText(explicitSize[1]);
    if (inchSize) return `${inchSize[1]} pouces`;
    if (cmSize) return `${cmSize[1]} cm`;
    if (modelSize) return `${modelSize[1]} pouces`;
    return '';
  };

  const getQuantityFromRow = (row) => {
    const label = row.querySelector('[data-testid="label-span"], .field__label_txt');
    const select = row.querySelector('select');
    return normalizeText(label?.textContent || select?.value || '');
  };

  const getCartDataFromDom = () => {
    const rows = Array.from(document.querySelectorAll('.cart-row'));
    const products = rows.map((row) => {
      const name = normalizeText(row.querySelector('#cart-row__product-label, .cart-row__product-label')?.textContent);
      const brand = normalizeText(row.querySelector('.cart-row__product-brand')?.textContent);
      const image = row.querySelector('.cart-row__item-img')?.currentSrc || row.querySelector('.cart-row__item-img')?.src || '';
      const price = formatPrice(row.querySelector('.cart-item-price__price')?.textContent);
      const quantity = getQuantityFromRow(row);
      const rowText = normalizeText(row.textContent);
      const size = extractSize(name, rowText);

      return {
        name: normalizeText(`${brand} ${name}`),
        image,
        size,
        price,
        quantity
      };
    }).filter((product) => product.name && product.image);

    return {
      products,
      total: normalizeText(document.querySelector('.cart-page-checkout-summary__amount')?.textContent),
      updatedAt: Date.now()
    };
  };

  const getCartDisplayFromDataLayer = () => {
    const dataLayer = window.dataLayer || [];
    const cartDisplay = dataLayer.slice().reverse().find((item) => item && item.event === 'cart.display' && Array.isArray(item.order_products));

    if (!cartDisplay) return null;

    const products = cartDisplay.order_products.map((product) => {
      const name = formatSlug(product.order_products_name || '');
      const ean = product.order_products_ean || '';
      const quantity = product.order_products_quantity ? String(product.order_products_quantity) : '';
      const price = formatPrice(product.order_products_unit_priceati || product.order_products_totalprice_ati);

      return {
        name,
        image: getImageFromEan(ean),
        size: extractSize(name, ''),
        price,
        quantity
      };
    }).filter((product) => product.name && product.image);

    return {
      products,
      total: formatPrice(cartDisplay.order_amount_ati_with_sf),
      updatedAt: Date.now()
    };
  };

  const saveCartData = (cartData) => {
    if (!cartData || !cartData.products || !cartData.products.length) return;
    localStorage.setItem(KAMELEOON_STORAGE_KEY, JSON.stringify(cartData));
    Kameleoon.API.Data.writeLocalData(KAMELEOON_STORAGE_KEY, JSON.stringify(cartData), true);
  };

  const readCartData = () => {
    const domData = getCartDataFromDom();
    if (domData.products.length) {
      saveCartData(domData);
      return domData;
    }

    const dataLayerData = getCartDisplayFromDataLayer();
    if (dataLayerData && dataLayerData.products.length) {
      saveCartData(dataLayerData);
      return dataLayerData;
    }

    try {
      const localData = localStorage.getItem(KAMELEOON_STORAGE_KEY) || Kameleoon.API.Data.readLocalData(KAMELEOON_STORAGE_KEY);
      return localData ? JSON.parse(localData) : null;
    } catch (error) {
      return null;
    }
  };

  const hasVisibleCartQuantity = () => {
    const quantity = Number(normalizeText(document.querySelector('.js-cart-quantity, .header__customer-qty')?.textContent));
    const storedQuantity = Number(localStorage.getItem('cartProductQuantity'));
    return quantity > 0 || storedQuantity > 0;
  };

  const shouldDisplayPopin = () => {
    const cartData = readCartData();
    return hasVisibleCartQuantity() && cartData && cartData.products && cartData.products.length;
  };

  const getProductsHtml = (products) => products.slice(0, 3).map((product) => {
    const size = product.size ? `<span class="kameleoonInsert kam-exit-popin__size">Taille : ${escapeHtml(product.size)}</span>` : '';
    const quantity = product.quantity ? `<span class="kameleoonInsert kam-exit-popin__quantity">Qté : ${escapeHtml(product.quantity)}</span>` : '';
    const price = product.price ? `<strong class="kameleoonInsert kam-exit-popin__price">${escapeHtml(product.price)}</strong>` : '';

    return `
      <div class="kameleoonInsert kam-exit-popin__product">
        <div class="kameleoonInsert kam-exit-popin__image-wrap">
          <img class="kameleoonInsert kam-exit-popin__image" src="${escapeHtml(product.image)}" alt="${escapeHtml(product.name)}">
        </div>
        <div class="kameleoonInsert kam-exit-popin__product-info">
          <p class="kameleoonInsert kam-exit-popin__product-name">${escapeHtml(product.name)}</p>
          <div class="kameleoonInsert kam-exit-popin__meta">${size}${quantity}${price}</div>
        </div>
      </div>
    `;
  }).join('');

  const buildPopin = (cartData) => {
    const wrapper = document.createElement('div');
    wrapper.className = 'kameleoonInsert kam-exit-popin';
    wrapper.innerHTML = `
      <div class="kameleoonInsert kam-exit-popin__overlay"></div>
      <section class="kameleoonInsert kam-exit-popin__modal" role="dialog" aria-modal="true" aria-labelledby="kam-exit-popin-title">
        <button type="button" class="kameleoonInsert kam-exit-popin__close" aria-label="Fermer">×</button>
        <div class="kameleoonInsert kam-exit-popin__header">
          <span class="kameleoonInsert kam-exit-popin__kicker">Votre panier vous attend</span>
          <h2 id="kam-exit-popin-title" class="kameleoonInsert kam-exit-popin__title">Ne laissez pas filer vos envies !</h2>
          <p class="kameleoonInsert kam-exit-popin__subtitle">Votre article est toujours disponible. Finalisez votre commande avant de quitter Boulanger.</p>
        </div>
        <div class="kameleoonInsert kam-exit-popin__products">${getProductsHtml(cartData.products)}</div>
        <a class="kameleoonInsert kam-exit-popin__loyalty" href="${LOYALTY_URL}">
          <span class="kameleoonInsert kam-exit-popin__loyalty-title">Le Club Boulanger</span>
          <span class="kameleoonInsert kam-exit-popin__loyalty-text">Cumulez des avantages fidélité et profitez d'offres exclusives toute l'année.</span>
        </a>
        <div class="kameleoonInsert kam-exit-popin__actions">
          <a class="kameleoonInsert kam-exit-popin__primary" href="${CART_URL}">Finaliser mon achat</a>
          <button type="button" class="kameleoonInsert kam-exit-popin__secondary">Continuer ma visite</button>
        </div>
      </section>
    `;
    return wrapper;
  };

  const closePopin = () => {
    const popin = document.querySelector('.kam-exit-popin');
    if (popin) popin.remove();
    state.isOpen = false;
  };

  const bindPopinEvents = (popin) => {
    popin.querySelectorAll('.kam-exit-popin__close, .kam-exit-popin__secondary, .kam-exit-popin__overlay').forEach((element) => {
      Kameleoon.API.Utils.addEventListener(element, 'click', closePopin);
    });

    Kameleoon.API.Utils.addEventListener(document.documentElement, 'keydown', (event) => {
      if (event.key === 'Escape') closePopin();
    });
  };

  const showPopin = () => {
    const now = Date.now();
    if (state.isOpen || now - state.lastTrigger < 600 || !shouldDisplayPopin()) return;

    const cartData = readCartData();
    const popin = buildPopin(cartData);
    state.isOpen = true;
    state.lastTrigger = now;
    document.body.appendChild(popin);
    bindPopinEvents(popin);
  };

  const persistAvailableCartData = () => {
    const domData = getCartDataFromDom();
    const dataLayerData = getCartDisplayFromDataLayer();
    saveCartData(domData.products.length ? domData : dataLayerData);
  };

  const patchDataLayer = () => {
    window.dataLayer = window.dataLayer || [];
    if (window.dataLayer.kamExitPatched) return;

    const originalPush = window.dataLayer.push;
    window.dataLayer.push = function patchedDataLayerPush(...items) {
      const result = originalPush.apply(this, items);
      items.forEach((item) => {
        if (item && item.event === 'cart.display') {
          Kameleoon.API.Utils.setTimeout(persistAvailableCartData, 50);
        }
      });
      return result;
    };
    window.dataLayer.kamExitPatched = true;
  };

  const bindExitIntent = () => {
    Kameleoon.API.Utils.addEventListener(document.documentElement, 'mouseout', (event) => {
      if (!event.relatedTarget && event.clientY <= 0) showPopin();
    });

    Kameleoon.API.Utils.addEventListener(document.documentElement, 'mouseleave', (event) => {
      if (event.clientY <= 0) showPopin();
    });
  };

  const init = () => {
    patchDataLayer();
    persistAvailableCartData();
    bindExitIntent();
  };

  Kameleoon.API.Core.runWhenElementPresent('body', init);
})();

