  function containsLikesText(text) {
    if (!text) return false;
    return /lieben\s+diesen\s+Artikel/i.test(text);
  }

  function findLikesBlock() {
    var nodes = document.querySelectorAll('span[data-bpds="typography"]');
    for (var i = 0; i < nodes.length; i++) {
      var el = nodes[i];
      var txt = (el.textContent || '').trim();
      if (containsLikesText(txt)) {
        var wrapper = el.closest('div');
        // Walk up until we find a div that contains the heart icon as well
        var cur = wrapper;
        while (cur && cur !== document.body) {
          if (cur.querySelector('svg[data-bpds="icon"]')) {
            wrapper = cur;
            break;
          }
          cur = cur.parentElement;
        }
        var svg = wrapper ? wrapper.querySelector('svg[data-bpds="icon"]') : null;
        return { textEl: el, wrapper: wrapper || el.parentElement, svg: svg };
      }
    }
    return null;
  }

  function extractCount(text) {
    if (!text) return '';
    var m = text.match(/([\d\.,\s]+)/);
    if (m && m[1]) {
      return m[1].trim();
    }
    var digits = (text.match(/\d+/g) || []).join('');
    if (!digits) return '';
    return digits.replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  }

