      if (prev && prev.querySelector('div[data-bpds="breadcrumb"]')) {
        return prev;
      }
    }
    // Fallback: common ancestor containing all breadcrumb nodes
    var crumbs = document.querySelectorAll('div[data-bpds="breadcrumb"]');
    if (crumbs.length) {
      var cur = crumbs[0].parentElement;
      while (cur && cur !== document.body) {
        var allInside = Array.prototype.every.call(crumbs, function (n) { return cur.contains(n); });
        if (allInside) {
          return cur;
