(() => {
  const POPUP_DELAY = 15000;
  const DISMISSED_STORAGE_KEY = 'kamIlumaPurplePopupDismissed';
  const CHECKOUT_PATH_FRAGMENT = '/check-out';
  const EN_PATH_FRAGMENT = '/en/';
  const AR_PATH_FRAGMENT = '/ar/';
  const EN_IMAGE_URL = 'https://mediagcc.iqos.com/sa.iqos.com/dw/image/v2/BFCT_PRD/on/demandware.static/-/Sites-iqos-sa-Library/default/experiments/exp_popup_purple/Pop-up_Banner_KSA_en.png';
  const AR_IMAGE_URL = 'https://mediagcc.iqos.com/sa.iqos.com/dw/image/v2/BFCT_PRD/on/demandware.static/-/Sites-iqos-sa-Library/default/experiments/exp_popup_purple/Pop-up_Banner_KSA_ar.png';
  const EN_PRODUCT_URL = 'https://sa.iqos.com/en/shop/iluma-devices?prefn1=refinementColor&prefv1=purple';
  const AR_PRODUCT_URL = 'https://sa.iqos.com/ar/shop/iluma-devices?prefn1=refinementColor&prefv1=purple';

  const isCheckoutPage = () => window.location.href.includes(CHECKOUT_PATH_FRAGMENT);

  const getLanguageConfig = () => {
    const currentUrl = window.location.href;
    const isArabic = currentUrl.includes(AR_PATH_FRAGMENT);

    return {
      imageUrl: isArabic ? AR_IMAGE_URL : EN_IMAGE_URL,
      productUrl: isArabic ? AR_PRODUCT_URL : EN_PRODUCT_URL,
      language: isArabic ? 'ar' : 'en'
    };
  };

  const hasPopupBeenDismissed = () => sessionStorage.getItem(DISMISSED_STORAGE_KEY) === 'true';

  const setPopupDismissed = () => {
    sessionStorage.setItem(DISMISSED_STORAGE_KEY, 'true');
  };

  const createPopup = () => {
    const config = getLanguageConfig();
    const overlay = document.createElement('div');
    const dialog = document.createElement('div');
    const link = document.createElement('a');
    const image = document.createElement('img');
    const closeButton = document.createElement('button');

    overlay.className = 'kameleoonInsert kam-iluma-popup-overlay';
    overlay.setAttribute('role', 'presentation');

    dialog.className = 'kam-iluma-popup-dialog';
    dialog.setAttribute('role', 'dialog');
    dialog.setAttribute('aria-modal', 'true');
    dialog.setAttribute('aria-label', config.language === 'ar' ? 'عرض IQOS ILUMA باللون البنفسجي' : 'IQOS ILUMA electric purple promotion');

    link.className = 'kam-iluma-popup-link';
    link.href = config.productUrl;
    link.setAttribute('aria-label', config.language === 'ar' ? 'تسوق IQOS ILUMA باللون البنفسجي' : 'Shop IQOS ILUMA electric purple');

    image.className = 'kam-iluma-popup-image';
    image.src = config.imageUrl;
    image.alt = config.language === 'ar' ? 'عرض IQOS ILUMA باللون البنفسجي' : 'IQOS ILUMA electric purple promotion';

    closeButton.className = 'kam-iluma-popup-close';
    closeButton.type = 'button';
    closeButton.setAttribute('aria-label', config.language === 'ar' ? 'إغلاق النافذة' : 'Close popup');
    closeButton.textContent = '×';

    link.appendChild(image);
    dialog.appendChild(link);
    dialog.appendChild(closeButton);
    overlay.appendChild(dialog);

    return { overlay, closeButton };
  };

  const removePopup = (overlay) => {
    overlay.classList.remove('kam-iluma-popup-visible');

    Kameleoon.API.Utils.setTimeout(() => {
      if (overlay.parentNode) {
        overlay.parentNode.removeChild(overlay);
      }
    }, 300);
  };

  const closePopup = (overlay) => {
    setPopupDismissed();
    removePopup(overlay);
  };

  const bindPopupEvents = (overlay, closeButton) => {
    Kameleoon.API.Utils.addUniversalClickListener(closeButton, (event) => {
      event.preventDefault();
      event.stopPropagation();
      closePopup(overlay);
    });

    Kameleoon.API.Utils.addUniversalClickListener(overlay, (event) => {
      if (event.target === overlay) {
        closePopup(overlay);
      }
    });
  };

  const showPopup = () => {
    if (isCheckoutPage() || hasPopupBeenDismissed() || document.querySelector('.kam-iluma-popup-overlay')) {
      return;
    }

    const { overlay, closeButton } = createPopup();

    document.body.appendChild(overlay);
    bindPopupEvents(overlay, closeButton);

    Kameleoon.API.Utils.setTimeout(() => {
      overlay.classList.add('kam-iluma-popup-visible');
    }, 50);
  };

  const schedulePopup = () => {
    if (isCheckoutPage() || hasPopupBeenDismissed()) {
      return;
    }

    Kameleoon.API.Utils.setTimeout(showPopup, POPUP_DELAY);
  };

  Kameleoon.API.Core.runWhenElementPresent('body', schedulePopup);
})();

