(function () {
  var OVERLAY_ID = 'km-hello-modal-overlay';

  function getFocusableElements(container) {
    if (!container) return [];
    var selectors = [
      'a[href]',
      'area[href]',
      'button:not([disabled])',
      'input:not([disabled]):not([type="hidden"])',
      'select:not([disabled])',
      'textarea:not([disabled])',
      '[tabindex]:not([tabindex="-1"])'
    ].join(',');

    return Array.prototype.slice
      .call(container.querySelectorAll(selectors))
      .filter(function (el) {
        return !!(el.offsetWidth || el.offsetHeight || el.getClientRects().length);
      });
  }

  function createModal() {
    var existing = document.getElementById(OVERLAY_ID);
    if (existing) return existing;

    var overlay = document.createElement('div');
    overlay.id = OVERLAY_ID;
    overlay.className = 'km-hello-modal-overlay';
    overlay.setAttribute('data-km-hello-modal', '');

    overlay.innerHTML =
      '<div class="km-hello-modal km-hello-modal--no-copy" role="dialog" aria-modal="true" aria-label="Dialog">' +
      '  <div class="km-hello-modal__header">' +
      '    <button type="button" class="km-hello-modal__close" aria-label="Close modal">' +
      '      <span aria-hidden="true">×</span>' +
      '      <span class="km-hello-modal__sr-only">Close</span>' +
      '    </button>' +
      '  </div>' +
      '  <div class="km-hello-modal__body"><p>Hello world</p></div>' +
      '</div>';

    document.body.appendChild(overlay);
    return overlay;
  }

  function openModal() {
    var overlay = createModal();
    if (!overlay) return;

    if (document.body) document.body.classList.add('km-hello-modal-open');

    var modal = overlay.querySelector('.km-hello-modal');
    var closeBtn = overlay.querySelector('.km-hello-modal__close');

    overlay.__kmPrevActiveEl = document.activeElement;

    if (closeBtn) {
      try {
        closeBtn.focus();
      } catch (e) {}
    } else if (modal) {
      modal.setAttribute('tabindex', '-1');
      try {
        modal.focus();
      } catch (e2) {}
    }
  }

  function closeModal() {
    var overlay = document.getElementById(OVERLAY_ID);
    if (!overlay) return;

    if (document.body) document.body.classList.remove('km-hello-modal-open');

    var prev = overlay.__kmPrevActiveEl;
    overlay.remove();

    if (prev && typeof prev.focus === 'function') {
      try {
        prev.focus();
      } catch (e) {}
    }
  }

  function bindModalEvents() {
    Kameleoon.API.Core.runWhenElementPresent('#' + OVERLAY_ID, function (elements) {
      var overlay = elements && elements[0];
      if (!overlay) return;

      var modal = overlay.querySelector('.km-hello-modal');
      var closeBtn = overlay.querySelector('.km-hello-modal__close');

      if (closeBtn) {
        Kameleoon.API.Utils.addEventListener(closeBtn, 'click', function (e) {
          e.preventDefault();
          closeModal();
        });
      }

      Kameleoon.API.Utils.addEventListener(overlay, 'mousedown', function (e) {
        if (e.target === overlay) closeModal();
      });

      Kameleoon.API.Utils.addEventListener(document, 'keydown', function (e) {
        var currentOverlay = document.getElementById(OVERLAY_ID);
        if (!currentOverlay) return;

        if (e.key === 'Escape' || e.key === 'Esc') {
          e.preventDefault();
          closeModal();
          return;
        }

        if (e.key !== 'Tab') return;
        if (!modal) return;

        var focusables = getFocusableElements(modal);
        if (!focusables.length) return;

        var first = focusables[0];
        var last = focusables[focusables.length - 1];
        var active = document.activeElement;

        if (e.shiftKey) {
          if (active === first || !modal.contains(active)) {
            e.preventDefault();
            last.focus();
          }
        } else {
          if (active === last) {
            e.preventDefault();
            first.focus();
          }
        }
      });
    });
  }

  function init() {
    if (document.getElementById(OVERLAY_ID)) return;
    bindModalEvents();
    openModal();
  }

  Kameleoon.API.Core.runWhenElementPresent('body', function () {
    init();
  });
})();

