(() => {
  const TOAST_ID = 'kam-add-to-bag-toast';
  const TOAST_VISIBLE_CLASS = 'kam-add-to-bag-toast--visible';
  const TOAST_DURATION = 6500;
  let hideTimer = null;

  const getProductCard = (button) => button.closest('.product-card') || button.closest('a') || button.closest('article');

  const getProductName = (card) => {
    if (!card) {
      return 'Selected product';
    }

    const textNodes = Array.from(card.querySelectorAll('p'))
      .map((element) => element.textContent.trim())
      .filter(Boolean);
    const image = card.querySelector('img');

    return textNodes[1] || textNodes[0] || (image && image.alt.trim()) || 'Selected product';
  };

  const getProductPrice = (card) => {
    if (!card) {
      return '';
    }

    const priceMatches = card.textContent.match(/€\s?\d+(?:[.,]\d{2})?/g) || [];
    return priceMatches.length ? priceMatches[priceMatches.length - 1].replace(/\s/g, '') : '';
  };

  const getProductImage = (card) => {
    const image = card ? card.querySelector('img') : null;

    return {
      src: image ? image.currentSrc || image.src : '',
      alt: image ? image.alt || getProductName(card) : getProductName(card)
    };
  };

  const getBagUrl = () => {
    const bagLink = Array.from(document.querySelectorAll('a[href]'))
      .find((link) => /cart|bag/i.test(link.href));

    return bagLink ? bagLink.href : '/cart';
  };

  const createButton = (label, className, href) => {
    const button = document.createElement('a');
    button.className = `kam-add-to-bag-toast__button ${className}`;
    button.href = href;
    button.textContent = label;

    return button;
  };

  const createToast = () => {
    const toast = document.createElement('div');
    toast.id = TOAST_ID;
    toast.className = 'kam-add-to-bag-toast kameleoonInsert';
    toast.setAttribute('role', 'status');
    toast.setAttribute('aria-live', 'polite');
    toast.setAttribute('aria-atomic', 'true');

    const title = document.createElement('h2');
    title.className = 'kam-add-to-bag-toast__title';
    title.textContent = 'Added to your shopping bag';

    const product = document.createElement('div');
    product.className = 'kam-add-to-bag-toast__product';

    const imageWrap = document.createElement('div');
    imageWrap.className = 'kam-add-to-bag-toast__image-wrap';

    const image = document.createElement('img');
    image.className = 'kam-add-to-bag-toast__image';
    imageWrap.appendChild(image);

    const copy = document.createElement('div');
    copy.className = 'kam-add-to-bag-toast__copy';

    const name = document.createElement('p');
    name.className = 'kam-add-to-bag-toast__name';

    const price = document.createElement('p');
    price.className = 'kam-add-to-bag-toast__price';

    copy.appendChild(name);
    copy.appendChild(price);
    product.appendChild(imageWrap);
    product.appendChild(copy);

    const actions = document.createElement('div');
    actions.className = 'kam-add-to-bag-toast__actions';
    actions.appendChild(createButton('Checkout', 'kam-add-to-bag-toast__button--checkout', '/checkout'));
    actions.appendChild(createButton('View bag', 'kam-add-to-bag-toast__button--bag', getBagUrl()));

    toast.appendChild(title);
    toast.appendChild(product);
    toast.appendChild(actions);
    document.body.appendChild(toast);

    return toast;
  };

  const getToast = () => document.getElementById(TOAST_ID) || createToast();

  const positionToast = (toast) => {
    const header = document.querySelector('header');
    const headerActions = document.querySelector('.header-actions');
    const headerBottom = header ? header.getBoundingClientRect().bottom : 0;
    const actionRight = headerActions ? headerActions.getBoundingClientRect().right : window.innerWidth - 32;
    const rightOffset = Math.max(16, Math.round(window.innerWidth - actionRight));
    const topOffset = Math.max(16, Math.round(headerBottom + 16));

    toast.style.setProperty('--kam-add-to-bag-top', `${topOffset}px`);
    toast.style.setProperty('--kam-add-to-bag-top-mobile', `${topOffset}px`);
    toast.style.setProperty('--kam-add-to-bag-right', `${rightOffset}px`);
  };

  const updateToastContent = (toast, card) => {
    const imageData = getProductImage(card);
    const name = getProductName(card);
    const price = getProductPrice(card);
    const image = toast.querySelector('.kam-add-to-bag-toast__image');
    const nameElement = toast.querySelector('.kam-add-to-bag-toast__name');
    const priceElement = toast.querySelector('.kam-add-to-bag-toast__price');
    const bagButton = toast.querySelector('.kam-add-to-bag-toast__button--bag');

    if (image) {
      image.src = imageData.src;
      image.alt = imageData.alt;
      image.hidden = !imageData.src;
    }

    if (nameElement) {
      nameElement.textContent = name;
    }

    if (priceElement) {
      priceElement.textContent = price;
      priceElement.hidden = !price;
    }

    if (bagButton) {
      bagButton.href = getBagUrl();
    }
  };

  const showToast = (card) => {
    const toast = getToast();

    positionToast(toast);
    updateToastContent(toast, card);

    if (hideTimer) {
      Kameleoon.API.Utils.clearTimeout(hideTimer);
    }

    requestAnimationFrame(() => {
      toast.classList.add(TOAST_VISIBLE_CLASS);
    });

    hideTimer = Kameleoon.API.Utils.setTimeout(() => {
      toast.classList.remove(TOAST_VISIBLE_CLASS);
      hideTimer = null;
    }, TOAST_DURATION);
  };

  const setupQuickAddButtons = (buttons) => {
    buttons.forEach((button) => {
      if (button.dataset.kamAddToBagBound === 'click-v2') {
        return;
      }

      button.dataset.kamAddToBagBound = 'click-v2';

      Kameleoon.API.Utils.addEventListener(button, 'click', (event) => {
        event.preventDefault();
        event.stopPropagation();
        showToast(getProductCard(button));
      });
    });
  };

  Kameleoon.API.Core.runWhenElementPresent('.quick-add', setupQuickAddButtons);
})();

