(function () {
  const PARTNER_OFFERS_SELECTOR = '#PartnerOffers';
  const NEXT_BUTTON_SELECTOR = 'button[id="carousel-menu-next-button"]';
  const PREV_BUTTON_SELECTOR = 'button[id="carousel-menu-prev-button"]';
  const AUTOPLAY_DELAY = 4000;

  const getKameleoonApi = () => window.Kameleoon.API;

  const prefersReducedMotion = () => window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches;

  const removePreviewControls = (carousel) => {
    carousel.querySelectorAll('.kam-auto-carousel-preview').forEach((element) => element.remove());
  };

  const getCarouselControls = (carousel) => ({
    nextButton: carousel.querySelector(NEXT_BUTTON_SELECTOR),
    prevButton: carousel.querySelector(PREV_BUTTON_SELECTOR)
  });

  const stopAutoplay = (state) => {
    if (!state.timeoutId) return;

    getKameleoonApi().Utils.clearTimeout(state.timeoutId);
    state.timeoutId = null;
  };

  const canAutoplay = (state) => !state.isHovering
    && !state.hasFocus
    && !document.hidden
    && !prefersReducedMotion();

  const scheduleAutoplay = (state, nextButton) => {
    stopAutoplay(state);

    if (!canAutoplay(state)) return;

    state.timeoutId = getKameleoonApi().Utils.setTimeout(() => {
      nextButton.click();
      scheduleAutoplay(state, nextButton);
    }, AUTOPLAY_DELAY);
  };

  const bindPauseInteractions = (carousel, state, nextButton) => {
    const api = getKameleoonApi();

    api.Utils.addEventListener(carousel, 'mouseenter', () => {
      state.isHovering = true;
      stopAutoplay(state);
    });

    api.Utils.addEventListener(carousel, 'mouseleave', () => {
      state.isHovering = false;
      scheduleAutoplay(state, nextButton);
    });

    api.Utils.addEventListener(carousel, 'focusin', () => {
      state.hasFocus = true;
      stopAutoplay(state);
    });

    api.Utils.addEventListener(carousel, 'focusout', (event) => {
      if (carousel.contains(event.relatedTarget)) return;

      state.hasFocus = false;
      scheduleAutoplay(state, nextButton);
    });

    api.Utils.addEventListener(document, 'visibilitychange', () => {
      if (document.hidden) {
        stopAutoplay(state);
        return;
      }

      scheduleAutoplay(state, nextButton);
    });
  };

  const bindManualControls = (carousel, state, nextButton, prevButton) => {
    const restartAutoplay = () => {
      scheduleAutoplay(state, nextButton);
    };

    getKameleoonApi().Utils.addUniversalClickListener(nextButton, restartAutoplay);

    if (prevButton) {
      getKameleoonApi().Utils.addUniversalClickListener(prevButton, restartAutoplay);
    }
  };

  const initialisePartnerOffersAutoplay = (carousel) => {
    if (!carousel || carousel.dataset.kameleoonPartnerOffersAutoplay === 'true') return;

    const { nextButton, prevButton } = getCarouselControls(carousel);
    if (!nextButton) return;

    carousel.dataset.kameleoonPartnerOffersAutoplay = 'true';
    carousel.classList.add('kam-partner-offers-autoplay');
    removePreviewControls(carousel);

