(function () {
  const PRODUCT_IMAGE_SELECTOR = 'main swiper-slide img';
  const ZOOM_BOX_CLASS = 'kam-product-zoom-box';
  const ZOOM_LENS_CLASS = 'kam-product-zoom-lens';
  const ZOOM_SCALE = 2.45;
  const BOX_OFFSET_X = 18;
  const BOX_OFFSET_Y = 18;
  const EDGE_GAP = 16;

  let zoomBox;
  let zoomLens;
  let activeImage;

  const isDesktopHoverDevice = () => window.matchMedia('(hover: hover) and (pointer: fine) and (min-width: 768px)').matches;

  const createZoomElements = () => {
    if (!zoomBox) {
      zoomBox = document.createElement('div');
      zoomBox.className = `kameleoonInsert ${ZOOM_BOX_CLASS}`;
      zoomBox.setAttribute('aria-hidden', 'true');
      document.body.appendChild(zoomBox);
    }

    if (!zoomLens) {
      zoomLens = document.createElement('div');
      zoomLens.className = `kameleoonInsert ${ZOOM_LENS_CLASS}`;
      zoomLens.setAttribute('aria-hidden', 'true');
      document.body.appendChild(zoomLens);
    }
  };

  const getRenderedImageMetrics = (image, imageRect) => {
    const naturalRatio = image.naturalWidth / image.naturalHeight;
    const renderedRatio = imageRect.width / imageRect.height;
    let renderedWidth = imageRect.width;
    let renderedHeight = imageRect.height;
    let offsetX = 0;
    let offsetY = 0;

    if (naturalRatio > renderedRatio) {
      renderedHeight = imageRect.width / naturalRatio;
      offsetY = (imageRect.height - renderedHeight) / 2;
    } else {
      renderedWidth = imageRect.height * naturalRatio;
      offsetX = (imageRect.width - renderedWidth) / 2;
    }

    return {
      renderedWidth,
      renderedHeight,
      offsetX,
      offsetY
    };
  };

  const clamp = (value, min, max) => Math.max(min, Math.min(max, value));

  const positionZoomBox = (event) => {
    const boxRect = zoomBox.getBoundingClientRect();
    const preferredLeft = event.clientX + BOX_OFFSET_X;
    const fallbackLeft = event.clientX - boxRect.width - BOX_OFFSET_X;
    const left = preferredLeft + boxRect.width + EDGE_GAP <= window.innerWidth
      ? preferredLeft
      : clamp(fallbackLeft, EDGE_GAP, window.innerWidth - boxRect.width - EDGE_GAP);
    const top = clamp(event.clientY + BOX_OFFSET_Y, EDGE_GAP, window.innerHeight - boxRect.height - EDGE_GAP);

    zoomBox.style.left = `${left}px`;
    zoomBox.style.top = `${top}px`;
  };

  const updateZoom = (event) => {
    if (!activeImage || !zoomBox || !zoomLens) {
      return;
    }

    const imageRect = activeImage.getBoundingClientRect();
    const metrics = getRenderedImageMetrics(activeImage, imageRect);
    const relativeX = clamp(event.clientX - imageRect.left - metrics.offsetX, 0, metrics.renderedWidth);
    const relativeY = clamp(event.clientY - imageRect.top - metrics.offsetY, 0, metrics.renderedHeight);
    const percentX = metrics.renderedWidth ? (relativeX / metrics.renderedWidth) * 100 : 50;
    const percentY = metrics.renderedHeight ? (relativeY / metrics.renderedHeight) * 100 : 50;
    const zoomBackgroundWidth = metrics.renderedWidth * ZOOM_SCALE;
    const zoomBackgroundHeight = metrics.renderedHeight * ZOOM_SCALE;

    positionZoomBox(event);

    zoomBox.style.backgroundImage = `url("${activeImage.currentSrc || activeImage.src}")`;
    zoomBox.style.backgroundSize = `${zoomBackgroundWidth}px ${zoomBackgroundHeight}px`;
    zoomBox.style.backgroundPosition = `${percentX}% ${percentY}%`;

    zoomLens.style.left = `${event.clientX}px`;
    zoomLens.style.top = `${event.clientY}px`;
  };

  const showZoom = (image, event) => {
    if (!isDesktopHoverDevice() || !image.complete || !image.naturalWidth) {
      return;
    }

    createZoomElements();
    activeImage = image;
    updateZoom(event);
    zoomBox.classList.add(`${ZOOM_BOX_CLASS}--visible`);
    zoomLens.classList.add(`${ZOOM_LENS_CLASS}--visible`);
  };

  const hideZoom = () => {
    activeImage = null;

    if (zoomBox) {
      zoomBox.classList.remove(`${ZOOM_BOX_CLASS}--visible`);
    }

    if (zoomLens) {
      zoomLens.classList.remove(`${ZOOM_LENS_CLASS}--visible`);
    }
  };

  const bindImageZoom = (image) => {
    if (image.dataset.kamZoomBound === 'true') {
      return;
    }

    image.dataset.kamZoomBound = 'true';

    Kameleoon.API.Utils.addEventListener(image, 'mouseenter', (event) => {
      showZoom(image, event);
    });

    Kameleoon.API.Utils.addEventListener(image, 'mousemove', (event) => {
      if (activeImage === image) {
        updateZoom(event);
      }
    });

    Kameleoon.API.Utils.addEventListener(image, 'mouseleave', hideZoom);
    Kameleoon.API.Utils.addEventListener(image, 'blur', hideZoom);
  };

  const initZoom = (images) => {
    images.forEach(bindImageZoom);
  };

  Kameleoon.API.Core.runWhenElementPresent(PRODUCT_IMAGE_SELECTOR, initZoom, null, true);
})();

