(() => {
  const KAMELEOON_STICKY_SELECTOR = '.kameleoon-sticky-category-header';
  const CATEGORY_TITLE_SELECTOR = '#js-product-list-top h1';
  const FILTER_BUTTON_SELECTOR = '#search_filter_toggler';
  const SORT_SELECT_SELECTOR = '#select-sort-order';

  const getCategoryTitle = () => {
    const titleElement = document.querySelector(CATEGORY_TITLE_SELECTOR);
    return titleElement ? titleElement.textContent.trim() : '';
  };

  const createStickyHeader = () => {
    const header = document.createElement('div');
    header.className = 'kameleoon-sticky-category-header kameleoonInsert';
    header.setAttribute('aria-hidden', 'true');

    const title = document.createElement('p');
    title.className = 'kameleoon-sticky-category-header__title';
    title.textContent = getCategoryTitle();

    const actions = document.createElement('div');
    actions.className = 'kameleoon-sticky-category-header__actions';

    const filterButton = document.createElement('button');
    filterButton.className = 'kameleoon-sticky-category-header__filter';
    filterButton.type = 'button';
    filterButton.textContent = 'Filtrer';

    actions.appendChild(filterButton);
    header.appendChild(title);
    header.appendChild(actions);

    return header;
  };

  const cloneSortSelect = (stickyHeader) => {
    const originalSelect = document.querySelector(SORT_SELECT_SELECTOR);
    const actions = stickyHeader.querySelector('.kameleoon-sticky-category-header__actions');

    if (!originalSelect || !actions || actions.querySelector('.kameleoon-sticky-category-header__sort')) {
      return;
    }

    const stickySelect = originalSelect.cloneNode(true);
    stickySelect.removeAttribute('id');
    stickySelect.className = 'kameleoon-sticky-category-header__sort';
    stickySelect.value = originalSelect.value;

    stickySelect.addEventListener('change', () => {
      originalSelect.value = stickySelect.value;
      originalSelect.dispatchEvent(new Event('change', { bubbles: true }));
    });

    actions.insertBefore(stickySelect, actions.firstChild);
  };

  const syncStickySortValue = (stickyHeader) => {
    const originalSelect = document.querySelector(SORT_SELECT_SELECTOR);
    const stickySelect = stickyHeader.querySelector('.kameleoon-sticky-category-header__sort');

    if (originalSelect && stickySelect && stickySelect.value !== originalSelect.value) {
      stickySelect.value = originalSelect.value;
    }
